#!/usr/bin/env python3
import base64
import gzip
import json
import re
import unicodedata
from pathlib import Path

EVENTS_PATH = Path("public/events/data/events.json")
RA_GZIP_BASE64 = """"""

def normalized(value):
    text = str(value or "").casefold()
    text = unicodedata.normalize("NFKD", text)
    text = "".join(ch for ch in text if not unicodedata.combining(ch))
    return re.sub(r"[^a-z0-9]+", " ", text).strip()

current = json.loads(EVENTS_PATH.read_text(encoding="utf-8"))
ra = json.loads(gzip.decompress(base64.b64decode(RA_GZIP_BASE64)).decode("utf-8"))

current_events = current.get("events", [])
ra_events = ra.get("events", [])

existing_ids = {str(event.get("id", "")) for event in current_events}
existing_date_titles = {
    (str(event.get("date", "")), normalized(event.get("title", "")))
    for event in current_events
}

added = []
skipped = []

for event in ra_events:
    event_id = str(event.get("id", ""))
    key = (str(event.get("date", "")), normalized(event.get("title", "")))
    if event_id in existing_ids or key in existing_date_titles:
        skipped.append(event)
        continue
    added.append(event)
    existing_ids.add(event_id)
    existing_date_titles.add(key)

merged = current_events + added
merged.sort(key=lambda event: (
    str(event.get("date", "")),
    str(event.get("title", "")).casefold(),
))

result = {
    "meta": current.get("meta", {}),
    "events": merged,
}

EVENTS_PATH.write_text(
    json.dumps(result, ensure_ascii=False, indent=2),
    encoding="utf-8",
)

print(f"Existing events: {len(current_events)}")
print(f"RA source events: {len(ra_events)}")
print(f"Added RA events: {len(added)}")
print(f"Skipped existing matches: {len(skipped)}")
print(f"Final event count: {len(merged)}")
